"use client";

import { Save } from "lucide-react";
import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";

import Layout from "@/components/Layout";
import {
  apiJson,
  errorMessage,
} from "@/lib/client/api";
import { notify } from "@/lib/notify";

const initialStudent = {
  school_id: "",
  first_name: "",
  middle_name: "",
  last_name: "",
  gender: "",
  phone: "",
  email: "",
  father_name: "",
  mother_name: "",
  father_phone: "",
  mother_phone: "",
  current_class_id: "",
  current_section_id: "",
};

export default function StudentsPage() {
  const router = useRouter();
  const [school, setSchool] =
    useState<any>(null);
  const [student, setStudent] =
    useState(initialStudent);
  const [classes, setClasses] =
    useState<any[]>([]);
  const [sections, setSections] =
    useState<any[]>([]);
  const [saving, setSaving] =
    useState(false);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [data, roster] =
        await Promise.all([
          apiJson<any>(
            "/api/my-school"
          ),
          apiJson<any>("/api/roster"),
        ]);

      setSchool(data);
      setClasses(
        Array.isArray(roster.classes)
          ? roster.classes
          : []
      );
      setSections(
        Array.isArray(roster.sections)
          ? roster.sections
          : []
      );
      setStudent((previous) => ({
        ...previous,
        school_id: data?.id || "",
      }));
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to load school"
        )
      );
    }
  };

  const updateField = (
    key: keyof typeof initialStudent,
    value: string
  ) => {
    setStudent((previous) => ({
      ...previous,
      [key]: value,
      ...(key === "current_class_id"
        ? {
            current_section_id: "",
          }
        : {}),
    }));
  };

  const filteredSections =
    sections.filter(
      (section) =>
        !student.current_class_id ||
        Number(section.class_id) ===
          Number(student.current_class_id)
    );

  const saveStudent = async () => {
    try {
      setSaving(true);
      await apiJson("/api/students", {
        method: "POST",
        headers: {
          "Content-Type":
            "application/json",
        },
        body: JSON.stringify(student),
      });

      notify.success(
        "Student saved successfully"
      );
      router.push("/students/list");
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to save student"
        )
      );
    } finally {
      setSaving(false);
    }
  };

  return (
    <Layout>
      <div className="mx-auto max-w-6xl space-y-6">
        <div>
          <h1 className="text-3xl font-black md:text-4xl">
            Student Admission
          </h1>
          <p className="mt-1 text-sm text-slate-600">
            Create a school-linked student record for the selected academic year.
          </p>
        </div>

        <div className="tt-card tt-card-pad">
          <h2 className="mb-3 text-lg font-black">
            School Information
          </h2>
          <input
            value={
              school?.school_name || ""
            }
            disabled
            className="input bg-slate-100"
          />
        </div>

        <div className="tt-card tt-card-pad">
          <div
            className="
              grid
              gap-4
              md:grid-cols-2
              xl:grid-cols-3
            "
          >
            <div className="rounded-lg border border-amber-200 bg-amber-50 p-4 xl:col-span-3">
              <p className="text-sm font-black text-slate-950">
                Admission and roll numbers are generated automatically.
              </p>
              <p className="mt-1 text-xs font-semibold leading-5 text-slate-600">
                Admission number is mandatory and will be generated on save using the school code and current year, for example KVS-AD-123/26. Enrollment number is optional for users and will also be generated as KVS-EN-123/26. Roll number is assigned after save by alphabetical first name order in the selected class and section.
              </p>
            </div>
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Gender
              </span>
              <select
                className="input"
                value={student.gender}
                onChange={(event) =>
                  updateField(
                    "gender",
                    event.target.value
                  )
                }
              >
                <option value="">
                  Select Gender
                </option>
                <option value="Male">
                  Male
                </option>
                <option value="Female">
                  Female
                </option>
              </select>
            </label>
            <Field
              label="First Name"
              required
              value={student.first_name}
              onChange={(value) =>
                updateField(
                  "first_name",
                  value
                )
              }
            />
            <Field
              label="Middle Name"
              value={student.middle_name}
              onChange={(value) =>
                updateField(
                  "middle_name",
                  value
                )
              }
            />
            <Field
              label="Last Name"
              value={student.last_name}
              onChange={(value) =>
                updateField(
                  "last_name",
                  value
                )
              }
            />
            <Field
              label="Phone"
              value={student.phone}
              onChange={(value) =>
                updateField(
                  "phone",
                  value
                )
              }
            />
            <Field
              label="Email"
              value={student.email}
              onChange={(value) =>
                updateField(
                  "email",
                  value
                )
              }
            />
            <Field
              label="Father Name"
              value={student.father_name}
              onChange={(value) =>
                updateField(
                  "father_name",
                  value
                )
              }
            />
            <Field
              label="Mother Name"
              value={student.mother_name}
              onChange={(value) =>
                updateField(
                  "mother_name",
                  value
                )
              }
            />
            <Field
              label="Father Phone"
              value={student.father_phone}
              onChange={(value) =>
                updateField(
                  "father_phone",
                  value
                )
              }
            />
            <Field
              label="Mother Phone"
              value={student.mother_phone}
              onChange={(value) =>
                updateField(
                  "mother_phone",
                  value
                )
              }
            />
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Class *
              </span>
              <select
                className="input"
                value={
                  student.current_class_id
                }
                onChange={(event) =>
                  updateField(
                    "current_class_id",
                    event.target.value
                  )
                }
              >
                <option value="">
                  Select Class
                </option>
                {classes.map((item) => (
                  <option
                    key={item.id}
                    value={item.id}
                  >
                    {item.class_name}
                  </option>
                ))}
              </select>
            </label>
            <label className="min-w-0">
              <span className="mb-1 block text-sm font-bold text-slate-700">
                Section *
              </span>
              <select
                className="input"
                value={
                  student.current_section_id
                }
                onChange={(event) =>
                  updateField(
                    "current_section_id",
                    event.target.value
                  )
                }
                disabled={
                  !student.current_class_id
                }
              >
                <option value="">
                  Select Section
                </option>
                {filteredSections.map(
                  (item) => (
                    <option
                      key={item.id}
                      value={item.id}
                    >
                      {item.section_name}
                    </option>
                  )
                )}
              </select>
            </label>
            <div className="rounded-lg border border-slate-200 bg-slate-50 p-4">
              <p className="text-sm font-bold text-slate-700">
                Roll Number
              </p>
              <p className="mt-2 text-sm font-black text-slate-950">
                Auto-generated after save
              </p>
            </div>
          </div>

          <button
            onClick={saveStudent}
            disabled={saving}
            className="tt-button mt-6 inline-flex items-center gap-2"
          >
            <Save size={17} />
            {saving
              ? "Saving..."
              : "Save Student"}
          </button>
        </div>
      </div>
    </Layout>
  );
}

function Field({
  label,
  value,
  onChange,
  required = false,
}: {
  label: string;
  value: string;
  onChange: (value: string) => void;
  required?: boolean;
}) {
  return (
    <label className="min-w-0">
      <span className="mb-1 block text-sm font-bold text-slate-700">
        {label}
        {required ? " *" : ""}
      </span>
      <input
        className="input"
        value={value}
        onChange={(event) =>
          onChange(event.target.value)
        }
      />
    </label>
  );
}
